// 1. Lấy item đầu tiên từ node Aggregate
const item = $input.first();

// 2. Lấy danh sách link (đang là mảng các chuỗi text)
// Dữ liệu lấy từ trường 'video_url'
const originalUrls = item.json.video_url; 

// 3. Biến đổi thành dạng [{"video_url": "link1"}, {"video_url": "link2"}]
const formattedList = originalUrls.map(url => ({
    video_url: url
}));

// 4. Tạo object tổng theo đúng cấu trúc yêu cầu
const finalObject = {
    video_urls: formattedList,
    id: "2323"
};

// 5. Trả về kết quả
// Quan trọng: Dùng JSON.stringify() để biến object thành chuỗi text như bạn muốn
return {
    json: {
        output: JSON.stringify(finalObject)
    }
};
